<?phpif ($rk[50]==0 and $status!='wg') exit;	echo '<table border="1" cellspacing="0" cellpadding="0" bordercolorlight=#C0C0C0 bordercolordark=#FFFFFF bgcolor=#F5F5F5 align=center>';		$dt = tme()-(3600*24*7);	$uid_list = Array();			$punishs = $db->sql('SELECT * FROM puns WHERE `date` > '.$dt.' ORDER BY `date` DESC');	while($punish = $db->fetchAssoc($punishs))	{		if ( !$uid_list[$punish['uid']] )		{			$uid_list[$punish['uid']] = $db->sqlr('SELECT `user` FROM `users` WHERE `uid` = '.$punish['uid'].';');		}				if ($punish["type"]==1) {$color = '#FFDDDD';$tt = 'МОЛЧАНИЕ';}		if ($punish["type"]==11) {$color = '#FFEEEE';$tt = 'Снято МОЛЧАНИЕ';}		if ($punish["type"]==2) {$color = '#DDAAAA';$tt = 'БЛОК';}		if ($punish["type"]==9) {$color = '#EEBBBB';$tt = 'Снято БЛОК';}		if ($punish["type"]==3) {$color = '#AADDAA';$tt = 'ТЮРЬМА';}		if ($punish["type"]==8) {$color = '#BBEEBB';$tt = 'Снято Тюрьма';}		if ($punish["type"]==4) {$color = '#AAAADD';$tt = 'КАРА';}		if ($punish["type"]==10) {$color = '#BBBBEE';$tt = 'Снято КАРА';}		if ($punish["type"]==5) {$color = '#AAAAFF';$tt = 'БЛОК ИНФЫ';}				if ($punish["type"]==15) {$color = '#AAAAFF';$tt = 'БЛАГОСЛОВЛЕНИЕ';}		if ($punish["type"]==16) {$color = '#BBBBEE';$tt = 'Снято БЛАГОСЛОВЛЕНИЕ';}				if ($punish["type"]==17) {$color = '#AAAAFF';$tt = 'Форумка';}		if ($punish["type"]==18) {$color = '#BBBBEE';$tt = 'Снято Форумка';}				echo "<tr>";		echo "<td bgcolor=".$color." class=timef>".date("d.m.y H:i:s",$punish["date"])."</td>";		echo "<td class=items>".$tt."</td>";		echo "<td class=user>".$punish["who"];		echo " <a href=info.php?".$punish["who"]." target=_blank>";		echo "<img src=images/i.gif></a>&nbsp;";		echo "</td>";		echo "<td class=timef>".tp($punish["duration"])."</td>";		echo "<td class=return_win>".$punish["reason"]."</td>";		echo "<td>&nbsp;=>&nbsp;<a href='info.php?".$uid_list[$punish['uid']]."' target=_blank><b>".$uid_list[$punish['uid']]."</b></a></td>";		echo "</tr>";	}	echo '</table>';?>